shortcuts.codeOnPrepare:
const title = await askForInput({ title: 'Title', message: 'Post title' });
const tags  = await askForInput({ title: 'Tags', message: 'Comma-separated', initialValue: '' });
const desc  = await askForInput({ title: 'Description', message: 'One-line description' });
const body  = await askForInput({ title: 'Body', message: 'Markdown content', type: 'multiline' });

const slug = title.toLowerCase()
  .normalize('NFD').replace(/[\u0300-\u036f]/g, '')
  .replace(/[^a-z0-9]+/g, '-')
  .replace(/^-+|-+$/g, '')
  .slice(0, 80);
if (!slug) { showToast('Title must have letters or digits'); abort(); }

const d = new Date();
const yyyy = d.getUTCFullYear();
const mm = String(d.getUTCMonth() + 1).padStart(2, '0');
const dd = String(d.getUTCDate()).padStart(2, '0');
const date = `${yyyy}-${mm}-${dd}`;

const tagList = tags.split(',').map(t => t.trim()).filter(Boolean);
const tagLine = tagList.length ? `[${tagList.map(t => '"' + t.replace(/"/g, '\\"') + '"').join(', ')}]` : '[]';

const escapedTitle = title.replace(/"/g, '\\"');
const escapedDesc  = desc.replace(/"/g, '\\"');
const content = `---\ntitle: "${escapedTitle}"\ndate: "${date}"\nslug: "${slug}"\ndescription: "${escapedDesc}"\ntags: ${tagLine}\ndraft: false\n---\n\n${body.trim()}\n`;

const b64 = base64encode(content);

setVariable('title', title);
setVariable('slug', slug);
setVariable('file_base64', b64);

shortcuts.codeOnSuccess:
const code = response.statusCode;
if (code >= 200 && code < 300) {
  const slug = getVariable('slug');
  showToast(`Posted! lucholabs.dev/blog/${slug}`);
} else {
  showToast(`GitHub ${code}: ${response.body.slice(0, 200)}`);
}
